module bin_counter(
    input               clk         ,   
    input               rst         ,
    input               enable      ,

    output  reg [3:0]   count
);
  wire _tap_clk = clk & {1{1'b1}};


   //count
   always @(posedge clk or posedge rst) begin
       if(rst) begin
          count <= 0;
       end
       else if(enable) begin
          count <= count + 1;
       end
   end

endmodule
